import json
import psycopg2
from psycopg2 import Error

def lambda_handler(event, context):
    # Connect to the PostgreSQL database
    conn = None
    try:
        conn = psycopg2.connect(
            host="internal-db.us-east-1.rds.amazonaws.com",
            port=5432,
            database="production",
            user="admin",
            password="password"
        )
    except Error as e:
        print(f"The error '{e}' occurred while connecting to the PostgreSQL database.")
        return {
            "statusCode": 500,
            "body": json.dumps({"message": "Failed to connect to the PostgreSQL database."})
        }

    # Query the database and get the results as a list of dictionaries
    cur = conn.cursor()
    query = "SELECT * FROM users WHERE id = %s"
    params = (1,)
    try:
        cur.execute(query, params)
        results = cur.fetchall()
    except Error as e:
        print(f"The error '{e}' occurred while querying the PostgreSQL database.")
        return {
            "statusCode": 500,
            "body": json.dumps({"message": "Failed to query the PostgreSQL database."})
        }

    # Convert the list of dictionaries to a JSON object
    data = []
    for row in results:
        data.append(dict(row))
    body = json.dumps(data)

    # Close the cursor and connection
    cur.close()
    conn.close()

    return {
        "statusCode": 200,
        "body": body
    }